#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2026/4/3# @Author : cyq# @File : interfaceDynamic# @Software: PyCharm# @Desc:from sqlalchemy import Integer, ForeignKey, Column, Stringfrom app.model import BaseModelclass InterfaceDynamic(BaseModel):    __tablename__ = "interface_dynamic"    interface_id = Column(Integer, ForeignKey("interface.id"), primary_key=True)    description = Column(String(500), nullable=False, comment="动态描述")    def __repr__(self):        return "<InterfaceDynamic %r %r>" % (self.interface_id, self.description)class InterfaceCaseDynamic(BaseModel):    __tablename__ = "interface_case_dynamic"    interface_case_id = Column(Integer, ForeignKey("interface_case.id"), primary_key=True)    description = Column(String(500), nullable=False, comment="动态描述")    def __repr__(self):        return "<InterfaceCaseDynamic %r %r>" % (self.interface_case_id, self.description)class InterfaceTaskDynamic(BaseModel):    __tablename__ = "interface_task_dynamic"    interface_task_id = Column(Integer, ForeignKey("interface_task.id"), primary_key=True)    description = Column(String(500), nullable=False, comment="动态描述")    def __repr__(self):        return "<InterfaceCaseDynamic %r %r>" % (self.interface_case_id, self.description)